queries.sparql:
PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?subject_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasSubjects ?child ; p:hasPhotographers ?parent . } GROUP BY ?child }
  ?child p:subject_name ?subject_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Photographers } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?subject_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasSubjects ?child ; p:hasPhotographers ?parent . } GROUP BY ?child }
  ?child p:subject_name ?subject_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Photographers } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?name ?subject_name WHERE {
  ?photographers_subjects a :Photographers_Subjects .
  ?subjects a :Subjects .
  ?photographers_subjects p:hasSubjects ?subjects .
  ?photographers a :Photographers .
  ?photographers_subjects p:hasPhotographers ?photographers .
  ?photographers p:name ?name .
  ?subjects p:subject_name ?subject_name .
} }
}
